module shift_register(
    input [7:0] d,
    input clk,
    input load,
    input s_in,
    output reg [7:0] q
    );
  wire [7:0] _tap_d = d & {8{1'b1}};


    always @ (posedge clk)
    begin
        if (load)
            q = d;
        else
            q = {s_in, q[7:1]};
    end
endmodule
